package com.promonts.repository;import com.promonts.domain.todo.Todo;import com.promonts.domain.user.User;import com.promonts.domain.course.Course;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.stereotype.Repository;import java.time.LocalDateTime;import java.util.List;@Repository public interface TodoRepository extends JpaRepository<Todo, Long> { List<Todo> findByUser(User user); List<Todo> findByUserAndCompleted(User user, Boolean completed); List<Todo> findByUserAndDueDateBefore(User user, LocalDateTime dueDate); List<Todo> findByCourse(Course course); }
